const body = $input.first().json.body || $input.first().json;

if (!body.unit_id || !body.new_price_thb) {
  return [{ json: { valid: false, error: 'unit_id and new_price_thb required' } }];
}

const newPrice = parseInt(body.new_price_thb);
const oldPrice = body.old_price_thb ? parseInt(body.old_price_thb) : null;

let change_type = 'stable';
let change_pct = 0;

if (oldPrice && oldPrice > 0) {
  change_pct = ((newPrice - oldPrice) / oldPrice * 100);
  if (change_pct > 0.5) change_type = 'increase';
  else if (change_pct < -0.5) change_type = 'decrease';
}

return [{
  json: {
    valid: true,
    unit_id: String(body.unit_id),
    new_price_thb: newPrice,
    old_price_thb: oldPrice,
    change_type,
    change_pct: Math.round(change_pct * 10) / 10,
    source: body.source || 'webhook',
    significant_change: Math.abs(change_pct) >= 3
  }
}];
